const all = $input.all();
const inicio = new Date('2025-01-01');

function parseDate(v) {
  if (!v || typeof v !== 'string') return null;
  if (v.includes('/')) { const [d,m,y] = v.split('/'); return new Date(`${y}-${m}-${d}`); }
  if (/^\d{4}-\d{2}-\d{2}/.test(v)) return new Date(v.slice(0,10));
  return null;
}

function keepSince2025(rec) {
  const d = rec.data_vencimento || rec.data_previsao || rec.data_emissao || rec.data_entrada;
  const dt = parseDate(d);
  return dt && dt >= inicio;
}

function esc(v) {
  const s = String(v ?? '');
  if (s.includes('"') || s.includes(',') || s.includes('\n')) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

function categoriaToText(rec) {
  if (Array.isArray(rec.categorias) && rec.categorias.length) {
    return rec.categorias.map(c => c.codigo_categoria || c.codigo || '').filter(Boolean).join('|');
  }
  return rec.codigo_categoria || rec.codigocategoria || '';
}

const linhas = [];

// Contas a Receber
if (all[0] && all[0].json && Array.isArray(all[0].json.conta_receber_cadastro)) {
  for (const r of all[0].json.conta_receber_cadastro) {
    if (!keepSince2025(r)) continue;
    linhas.push({
      tipo: 'conta_receber',
      codigo_lancamento_omie: r.codigo_lancamento_omie || '',
      codigo_lancamento_integracao: r.codigo_lancamento_integracao || '',
      codigo_cliente_fornecedor: r.codigo_cliente_fornecedor || '',
      codigo_categoria: categoriaToText(r),
      data_emissao: r.data_emissao || '',
      data_previsao: r.data_previsao || '',
      data_vencimento: r.data_vencimento || '',
      data_registro: r.data_registro || '',
      status_titulo: r.status_titulo || '',
      valor_documento: r.valor_documento || '',
      numero_documento_fiscal: r.numero_documento_fiscal || '',
      numero_parcela: r.numero_parcela || '',
      id_conta_corrente: r.id_conta_corrente || '',
      id_origem: r.id_origem || ''
    });
  }
}

// Contas a Pagar
if (all[1] && all[1].json && Array.isArray(all[1].json.conta_pagar_cadastro)) {
  for (const r of all[1].json.conta_pagar_cadastro) {
    if (!keepSince2025(r)) continue;
    linhas.push({
      tipo: 'conta_pagar',
      codigo_lancamento_omie: r.codigo_lancamento_omie || '',
      codigo_lancamento_integracao: r.codigo_lancamento_integracao || '',
      codigo_cliente_fornecedor: r.codigo_cliente_fornecedor || '',
      codigo_categoria: categoriaToText(r),
      data_emissao: r.data_emissao || '',
      data_previsao: r.data_previsao || '',
      data_vencimento: r.data_vencimento || '',
      data_registro: r.data_registro || '',
      status_titulo: r.status_titulo || '',
      valor_documento: r.valor_documento || '',
      numero_documento_fiscal: r.numero_documento_fiscal || '',
      numero_parcela: r.numero_parcela || '',
      id_conta_corrente: r.id_conta_corrente || '',
      id_origem: r.id_origem || ''
    });
  }
}

const headers = [
  'tipo','codigo_lancamento_omie','codigo_lancamento_integracao','codigo_cliente_fornecedor','codigo_categoria',
  'data_emissao','data_previsao','data_vencimento','data_registro','status_titulo','valor_documento',
  'numero_documento_fiscal','numero_parcela','id_conta_corrente','id_origem'
];

const csv = [headers.join(',')]
  .concat(linhas.map(l => headers.map(h => esc(l[h])).join(',')))
  .join('\n');

return [{ json: { total_linhas: linhas.length, csv } }];
